// FIX #1 — Comprehensive input validation
const raw = $input.first().json;
const body = raw.body || raw;

const errors = [];
const missing_fields = [];

// Check required fields
const required = ['business_name', 'email', 'website_url'];
for (const field of required) {
  if (!body[field] || String(body[field]).trim() === '') {
    missing_fields.push(field);
  }
}
// Accept both telegram_id and telegram_chat_id
const telegramRaw = body.telegram_chat_id || body.telegram_id || '';
if (!telegramRaw || String(telegramRaw).trim() === '') {
  missing_fields.push('telegram_id');
}

// Support multiple WC key naming conventions
const ck = body.consumer_key || body.wc_consumer_key || body.woocommerce_consumer_key || '';
const cs = body.consumer_secret || body.wc_consumer_secret || body.woocommerce_consumer_secret || '';

if (!ck) missing_fields.push('consumer_key');
if (!cs) missing_fields.push('consumer_secret');

if (missing_fields.length > 0) {
  return [{ json: { valid: false, errors: ['Missing required fields: ' + missing_fields.join(', ')], missing_fields } }];
}

// Format validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  errors.push('Invalid email format');
}

// Accept both telegram_id and telegram_chat_id
const telegramId = String(telegramRaw).trim();
if (!/^-?\d+$/.test(telegramId)) {
  errors.push('telegram_id must be a numeric Telegram chat ID (e.g. 123456789 or -100123456789)');
}

const urlRegex = /^https?:\/\/.+/;
if (!urlRegex.test(body.website_url)) {
  errors.push('website_url must start with http:// or https://');
}

if (!ck.startsWith('ck_')) {
  errors.push('consumer_key must start with ck_');
}

if (!cs.startsWith('cs_')) {
  errors.push('consumer_secret must start with cs_');
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors, missing_fields: [] } }];
}

return [{
  json: {
    valid: true,
    errors: [],
    missing_fields: [],
    business_name: String(body.business_name).trim(),
    email: String(body.email).trim().toLowerCase(),
    telegram_chat_id: telegramId,
    website_url: String(body.website_url).trim().replace(/\/$/, ''),
    consumer_key: ck,
    consumer_secret: cs,
    business_description: body.business_description || '',
    industry: body.industry || ''
  }
}];

const data = $('Validate Inputs').first().json;

function randomHex(len) {
  const chars = '0123456789abcdef';
  let result = '';
  for (let i = 0; i < len; i++) {
    result += chars[Math.floor(Math.random() * 16)];
  }
  return result;
}

// Add timestamp + counter entropy to reduce collision chance
const ts = Date.now().toString(16);
const rand1 = randomHex(48) + ts;
const rand2 = randomHex(48) + ts.split('').reverse().join('');

return [{
  json: {
    ...data,
    status: 'active',
    registered_at: new Date().toISOString(),
    api_key: rand1.substring(0, 64),
    webhook_secret: rand2.substring(0, 64)
  }
}];

// Normalize PostgREST response: handles array, vnd.pgrst wrapped string, or direct object
const raw = $input.first().json;
if (raw.error || raw.message) return [{ json: raw }];
if (raw.data && typeof raw.data === 'string') {
  try { return [{ json: JSON.parse(raw.data) }]; } catch(e) {}
}
if (Array.isArray(raw)) return [{ json: raw[0] || {} }];
return [{ json: raw }];

// Normalize PostgREST response: handles array, vnd.pgrst wrapped string, or direct object
const raw = $input.first().json;
if (raw.error || raw.message) return [{ json: raw }];
if (raw.data && typeof raw.data === 'string') {
  try { return [{ json: JSON.parse(raw.data) }]; } catch(e) {}
}
if (Array.isArray(raw)) return [{ json: raw[0] || {} }];
return [{ json: raw }];

const creds = $('Validate Inputs').first().json;
return [{
  json: {
    _order_url: creds.website_url.replace(/\/+$/, '') + '/wp-json/wc/v3/orders',
    _order_ck: creds.consumer_key,
    _order_cs: creds.consumer_secret,
    _order_page: 1,
    _order_per_page: 100,
    _order_total_fetched: 0,
    _order_line_items_count: 0,
    _order_has_more: true
  }
}];

// Get pagination state — falls back to Prepare Order Fetch on first iteration
let state;
try {
  state = $('Prepare Next Orders Page').first().json;
} catch (e) {
  state = $('Prepare Order Fetch').first().json;
}

const httpResp = $input.first().json;
const business_id = $('Store Business Profile').first().json.business_id;

// Handle fetch error
if (httpResp.error || (httpResp.statusCode && httpResp.statusCode >= 400)) {
  return [{
    json: {
      ...state,
      _order_has_more: false,
      _order_batch: [],
      _order_line_items_batch: [],
      _order_refunds_batch: [],
      _order_error: httpResp.error || ('HTTP ' + httpResp.statusCode)
    }
  }];
}

const orders = Array.isArray(httpResp.body) ? httpResp.body : [];
const totalPages = parseInt((httpResp.headers || {})['x-wp-totalpages'] || '1');
const hasMore = orders.length >= state._order_per_page && state._order_page <= totalPages;

// Transform orders for woocommerce_orders table
const orderBatch = orders.map(o => ({
  business_id,
  wc_order_id: o.id,
  order_number: String(o.number || o.id),
  status: o.status || 'pending',
  currency: o.currency || 'USD',
  total: parseFloat(o.total) || 0,
  total_refunded: parseFloat(o.total_refunded) || 0,
  subtotal: parseFloat(o.subtotal) || 0,
  tax_total: parseFloat(o.total_tax) || 0,
  shipping_total: parseFloat(o.shipping_total) || 0,
  discount_total: parseFloat(o.discount_total) || 0,
  customer_email: o.billing && o.billing.email ? o.billing.email : null,
  customer_phone: o.billing && o.billing.phone ? o.billing.phone : null,
  customer_name: o.billing ? ((o.billing.first_name || '') + ' ' + (o.billing.last_name || '')).trim() || null : null,
  billing_address: o.billing || {},
  shipping_address: o.shipping || {},
  line_items: o.line_items || [],
  payment_method: o.payment_method || null,
  payment_method_title: o.payment_method_title || null,
  transaction_id: o.transaction_id || null,
  date_created: o.date_created || null,
  date_modified: o.date_modified || null,
  date_completed: o.date_completed || null,
  date_paid: o.date_paid || null,
  last_synced_at: new Date().toISOString()
}));

// Extract line items for woocommerce_order_items table
const lineItemsBatch = [];
for (const o of orders) {
  for (const item of (o.line_items || [])) {
    if (!item.id) continue;
    lineItemsBatch.push({
      business_id,
      wc_order_id: o.id,
      wc_order_item_id: item.id,
      product_id: item.product_id || null,
      variation_id: item.variation_id || null,
      product_name: (item.name || 'Unknown').substring(0, 500),
      sku: item.sku || null,
      quantity: parseInt(item.quantity) || 1,
      price: parseFloat(item.price) || 0,
      subtotal: parseFloat(item.subtotal) || 0,
      total: parseFloat(item.total) || 0,
      tax: parseFloat(item.total_tax) || 0,
      order_date: o.date_created || null,
      order_status: o.status || null,
      last_synced_at: new Date().toISOString()
    });
  }
}

// Extract refunds for woocommerce_refunds table
// WooCommerce includes refunds[] on each order: { id, reason, total (negative) }
const refundsBatch = [];
for (const o of orders) {
  for (const refund of (o.refunds || [])) {
    if (!refund.id) continue;
    refundsBatch.push({
      business_id,
      wc_refund_id: refund.id,
      wc_order_id: o.id,
      reason: refund.reason || null,
      total: Math.abs(parseFloat(refund.total) || 0),
      last_synced_at: new Date().toISOString()
    });
  }
}

return [{
  json: {
    ...state,
    _order_page: state._order_page + 1,
    _order_total_fetched: (state._order_total_fetched || 0) + orders.length,
    _order_line_items_count: (state._order_line_items_count || 0) + lineItemsBatch.length,
    _order_refunds_count: (state._order_refunds_count || 0) + refundsBatch.length,
    _order_has_more: hasMore,
    _order_batch: orderBatch,
    _order_line_items_batch: lineItemsBatch,
    _order_refunds_batch: refundsBatch
  }
}];

const business_id = $('Store Business Profile').first().json.business_id;

// Extract unique customers from last processed orders batch
let orderBatch = [];
try {
  const orderData = $('Process Orders Page').first().json;
  orderBatch = orderData._order_batch || [];
} catch(e) { orderBatch = []; }

const seen = new Set();
const customers = [];

for (const order of orderBatch) {
  if (!order.customer_email) continue;
  const emailKey = order.customer_email.toLowerCase();
  if (seen.has(emailKey)) continue;
  seen.add(emailKey);
  customers.push({
    business_id,
    wc_customer_id: order.wc_order_id || null,
    name: order.customer_name || 'Unknown',
    email: order.customer_email,
    phone_number: order.customer_phone || null
  });
}

if (customers.length === 0) {
  return [{ json: { business_id, customers_found: 0, skipped: true } }];
}

return customers.map(c => ({ json: c }));

// Collect results and warnings from all parallel branches
const warnings = [];

// Products sync results
let products_count = 0;
try {
  const pd = $('Finalize Products Sync').first().json;
  products_count = pd.products_count || 0;
  if (pd.products_sync_error) warnings.push('Products: ' + pd.products_sync_error);
} catch (e) { warnings.push('Products sync data unavailable: ' + e.message); }

// Orders sync results
let orders_count = 0;
try {
  const od = $('Process Orders Page').first().json;
  orders_count = od._order_total_fetched || 0;
  if (od._order_error) warnings.push('Orders: ' + od._order_error);
} catch (e) { warnings.push('Orders sync unavailable: ' + e.message); }

// Line items count
let line_items_count = 0;
try {
  line_items_count = $('Process Orders Page').first().json._order_line_items_count || 0;
} catch (e) {}

// Customers count
let customers_count = 0;
try {
  customers_count = $('Insert Customers to Supabase').all().filter(i => !i.json.error).length;
} catch (e) {}

// WooCommerce webhook status
let webhook_created = false;
try {
  const wh = $('Create WooCommerce Webhook').first().json;
  webhook_created = !!(wh && wh.id);
  if (!webhook_created) warnings.push('WC webhook creation: ' + (wh.error || 'failed'));
} catch (e) { warnings.push('WC webhook creation failed: ' + e.message); }

// Gmail status
try {
  const gm = $('Send Gmail Welcome').first().json;
  if (gm.error) warnings.push('Welcome email: ' + gm.error);
} catch (e) { warnings.push('Welcome email unavailable'); }

// Telegram welcome status
try {
  const tg = $('Send Telegram Welcome').first().json;
  if (tg.error) warnings.push('Telegram welcome: ' + tg.error);
} catch (e) { warnings.push('Telegram welcome unavailable'); }

return [{
  json: {
    success: true,
    business_id: $('Store Business Profile').first().json.business_id,
    api_key: $('Get API Credentials').first().json.api_key,
    message: warnings.length > 0 ? 'Business registered with warnings' : 'Business registered successfully',
    sync_results: {
      products_synced: products_count,
      orders_synced: orders_count,
      line_items_synced: line_items_count,
      customers_synced: customers_count,
      webhook_created
    },
    warnings,
    registered_at: $('Store Business Profile').first().json.registered_at,
    lead_capture_webhook_url: 'https://n8n.mtsolutions.fun/webhook/lead-capture',
    integration_instructions: 'Include your business_id in all lead capture requests'
  }
}];

const creds = $('Validate Inputs').first().json;
return [{
  json: {
    _wc_url: creds.website_url.replace(/\/+$/, '') + '/wp-json/wc/v3/products',
    _wc_ck: creds.consumer_key,
    _wc_cs: creds.consumer_secret,
    _wc_page: 1,
    _wc_per_page: 100,
    _wc_total_fetched: 0,
    _wc_has_more: true
  }
}];

// Get current pagination state — first iteration: PrepFetch, subsequent: PrepNextPage
let state;
try {
  state = $('Prepare Next Product Page').first().json;
} catch (e) {
  state = $('Prepare Product Fetch').first().json;
}

const httpResp = $input.first().json;
const business_id = $('Store Business Profile').first().json.business_id;

// Handle fetch error
if (httpResp.error || (httpResp.statusCode && httpResp.statusCode >= 400)) {
  return [{
    json: {
      ...state,
      _wc_has_more: false,
      _wc_batch: [],
      _wc_error: httpResp.error || ('HTTP ' + httpResp.statusCode)
    }
  }];
}

const products = Array.isArray(httpResp.body) ? httpResp.body : [];
const totalPages = parseInt((httpResp.headers || {})['x-wp-totalpages'] || '1');
const hasMore = products.length >= state._wc_per_page && state._wc_page <= totalPages;

const batch = products.map(p => ({
  business_id,
  wc_product_id: p.id,
  name: (p.name || 'Unknown').substring(0, 500),
  slug: (p.slug || '').substring(0, 500) || null,
  sku: p.sku || null,
  price: parseFloat(p.price) || 0,
  regular_price: parseFloat(p.regular_price) || 0,
  sale_price: p.sale_price ? parseFloat(p.sale_price) : null,
  stock_quantity: p.stock_quantity || 0,
  stock_status: p.stock_status || 'instock',
  description: (p.description || '').substring(0, 5000) || null,
  short_description: (p.short_description || '').substring(0, 2000) || null,
  categories: p.categories || [],
  images: (p.images || []).map(img => ({ id: img.id, src: img.src, alt: img.alt })),
  last_synced_at: new Date().toISOString()
}));

return [{
  json: {
    ...state,
    _wc_page: state._wc_page + 1,
    _wc_total_fetched: state._wc_total_fetched + products.length,
    _wc_has_more: hasMore,
    _wc_batch: batch
  }
}];

// Pass updated state forward for next fetch iteration
const state = $('Process Products Page').first().json;
return [{ json: { ...state } }];

let state;
try {
  state = $('Process Products Page').first().json;
} catch (e) {
  state = { _wc_total_fetched: 0 };
}
return [{
  json: {
    products_count: state._wc_total_fetched || 0,
    products_sync_error: state._wc_error || null
  }
}];

// Pass updated pagination state forward for next fetch iteration
const state = $('Process Orders Page').first().json;
return [{ json: { ...state } }];
